mapper.select:
select distinct i.activity_id from osh_seckill_activity_item i inner join osh_seckill_activity a on i.activity_id = a.id where a.status != 0 and a.status != 4 and a.start_time <= NOW() and a.end_time >= NOW() and (a.delete_flag = 0 or a.delete_flag is null) and (i.delete_flag = 0 or i.delete_flag is null)
and i.title like concat('%', #{title}, '%')
and i.goods_type = #{goodsType}

mapper.update:
update osh_seckill_activity_item
title = #{title}, cover = #{cover}, seckill_price = #{seckillPrice}, total_stock = #{totalStock}, available_stock = #{availableStock}, limit_per_user = #{limitPerUser}, sort = #{sort}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP,
where id = #{id}

update osh_seckill_activity_item
set available_stock = available_stock - #{quantity},
    sold_count      = sold_count + #{quantity},
    update_time     = CURRENT_TIMESTAMP
where id = #{id}
  and available_stock >= #{quantity}
